import{_ as e,o as r,c as d,ag as i}from"./chunks/framework.BZohXCq9.js";const m=JSON.parse('{"title":"bamdra-user-bind","description":"Bamdra OpenClaw 套件中身份与画像绑定插件 bamdra-user-bind 的产品介绍。","frontmatter":{"title":"bamdra-user-bind","description":"Bamdra OpenClaw 套件中身份与画像绑定插件 bamdra-user-bind 的产品介绍。"},"headers":[],"relativePath":"zh/guide/user-bind.md","filePath":"zh/guide/user-bind.md","lastUpdated":null}'),l={name:"zh/guide/user-bind.md"};function n(t,a,o,s,b,u){return r(),d("div",null,[...a[0]||(a[0]=[i('<h1 id="bamdra-user-bind" tabindex="-1">bamdra-user-bind <a class="header-anchor" href="#bamdra-user-bind" aria-label="Permalink to &quot;bamdra-user-bind&quot;">​</a></h1><p><code>bamdra-user-bind</code> 是 Bamdra OpenClaw 套件里的身份层插件，但它本身也可以独立运行。</p><h2 id="它解决什么问题" tabindex="-1">它解决什么问题 <a class="header-anchor" href="#它解决什么问题" aria-label="Permalink to &quot;它解决什么问题&quot;">​</a></h2><p>很多运行时只能拿到飞书、Telegram、WhatsApp 这类 channel 暴露出的原始 sender ID，这不足以构建稳定的用户边界。<code>bamdra-user-bind</code> 的作用，就是把这些不稳定的 channel 身份映射成稳定的用户身份模型。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li>多 channel 身份解析</li><li>飞书 OpenID 到真实用户身份转换</li><li>本地 SQLite 用户画像存储与导出</li><li>普通 agent 只能读取当前用户资料</li><li>管理员工具支持自然语言查询和编辑</li></ul><h2 id="为什么重要" tabindex="-1">为什么重要 <a class="header-anchor" href="#为什么重要" aria-label="Permalink to &quot;为什么重要&quot;">​</a></h2><p>如果没有身份层，长期记忆很容易出现同一个人被拆成多条记录、不同用户数据串读、或者错误挂到原始 sender ID 上的问题。<code>bamdra-user-bind</code> 就是用来解决这个问题的。</p><h2 id="它和其他插件的关系" tabindex="-1">它和其他插件的关系 <a class="header-anchor" href="#它和其他插件的关系" aria-label="Permalink to &quot;它和其他插件的关系&quot;">​</a></h2><ul><li>自己就能独立作为身份插件运行</li><li>当通过 npm 安装 <code>bamdra-openclaw-memory</code> 时，会作为依赖被自动补齐</li><li>也可以单独安装到其他运行时里使用</li></ul><h2 id="仓库" tabindex="-1">仓库 <a class="header-anchor" href="#仓库" aria-label="Permalink to &quot;仓库&quot;">​</a></h2><ul><li>GitHub: <a href="https://github.com/bamdra/bamdra-user-bind" target="_blank" rel="noreferrer">bamdra/bamdra-user-bind</a></li><li>全部仓库入口: <a href="https://github.com/bamdra" target="_blank" rel="noreferrer">github.com/bamdra</a></li></ul>',12)])])}const c=e(l,[["render",n]]);export{m as __pageData,c as default};
